import copy
import gzip
import inspect
import logging
import pickle
import threading
import zlib
from functools import wraps
from hashlib import sha256
from typing import Any, Dict, Optional

import cloudpickle
import pydantic
import ujson
from cachetools import LRUCache, TTLCache
from diskcache import FanoutCache

_COMPRESSION_MAGIC = b"DSPC"
_COMPRESSION_CODECS = {None: 0, "gzip": 1, "zlib": 2}

logger = logging.getLogger(__name__)


class Cache:
    """DSPy Cache

    `Cache` provides 2 levels of caching (in the given order):
        1. In-memory cache - implemented with cachetools.LRUCache
        2. On-disk cache - implemented with diskcache.FanoutCache
    """

    def __init__(
        self,
        enable_disk_cache: bool,
        enable_memory_cache: bool,
        disk_cache_dir: str,
        disk_size_limit_bytes: Optional[int] = 1024 * 1024 * 10,
        memory_max_entries: Optional[int] = 1000000,
        ttl: Optional[int] = None,
        compress: Optional[str] = None,
        cull_limit: Optional[int] = None,
        eviction_policy: Optional[str] = None,
    ):
        """
        Args:
            enable_disk_cache: Whether to enable on-disk cache.
            enable_memory_cache: Whether to enable in-memory cache.
            disk_cache_dir: The directory where the disk cache is stored.
            disk_size_limit_bytes: The maximum size of the disk cache (in bytes).
            memory_max_entries: The maximum size of the in-memory cache (in number of items).
            ttl: The default time-to-live in seconds for cache entries. `None` means entries never expire.
            compress: Compression codec for on-disk cache entries (`"gzip"`, `"zlib"`, or `None` to disable).
            cull_limit: Number of items culled per eviction pass on the disk cache. `None` keeps the diskcache
                default.
            eviction_policy: Eviction policy for the on-disk cache (e.g. `"least-recently-stored"`,
                `"least-recently-used"`, `"least-frequently-used"`, `"none"`). `None` keeps the diskcache default.
        """

        self.enable_disk_cache = enable_disk_cache
        self.enable_memory_cache = enable_memory_cache
        self.memory_max_entries = memory_max_entries
        self.default_ttl = ttl
        self.compress = compress
        if self.enable_memory_cache:
            if ttl is not None:
                self.memory_cache = TTLCache(maxsize=memory_max_entries, ttl=ttl)
            else:
                self.memory_cache = LRUCache(maxsize=memory_max_entries)
        else:
            self.memory_cache = {}
        if self.enable_disk_cache:
            disk_cache_kwargs = {
                "shards": 16,
                "timeout": 10,
                "directory": disk_cache_dir,
                "size_limit": disk_size_limit_bytes,
            }
            if cull_limit is not None:
                disk_cache_kwargs["cull_limit"] = cull_limit
            if eviction_policy is not None:
                disk_cache_kwargs["eviction_policy"] = eviction_policy
            self.disk_cache = FanoutCache(**disk_cache_kwargs)
        else:
            self.disk_cache = {}

        self._lock = threading.RLock()

    def __contains__(self, key: str) -> bool:
        """Check if a key is in the cache."""
        return key in self.memory_cache or key in self.disk_cache

    def cache_key(self, request: Dict[str, Any], ignored_args_for_cache_key: Optional[list[str]] = None) -> str:
        """
        Obtain a unique cache key for the given request dictionary by hashing its JSON
        representation. For request fields having types that are known to be JSON-incompatible,
        convert them to a JSON-serializable format before hashing.
        """

        ignored_args_for_cache_key = ignored_args_for_cache_key or []

        def transform_value(value):
            if isinstance(value, type) and issubclass(value, pydantic.BaseModel):
                return value.model_json_schema()
            elif isinstance(value, pydantic.BaseModel):
                return value.model_dump()
            elif callable(value):
                # Try to get the source code of the callable if available
                import inspect

                try:
                    # For regular functions, we can get the source code
                    return f"<callable_source:{inspect.getsource(value)}>"
                except (TypeError, OSError):
                    # For lambda functions or other callables where source isn't available,
                    # use a string representation
                    return f"<callable:{value.__name__ if hasattr(value, '__name__') else 'lambda'}>"
            elif isinstance(value, dict):
                return {k: transform_value(v) for k, v in value.items()}
            else:
                return value

        params = {k: transform_value(v) for k, v in request.items() if k not in ignored_args_for_cache_key}
        return sha256(ujson.dumps(params, sort_keys=True).encode()).hexdigest()

    def get(self, request: Dict[str, Any], ignored_args_for_cache_key: Optional[list[str]] = None) -> Any:
        try:
            key = self.cache_key(request, ignored_args_for_cache_key)
        except Exception:
            logger.debug(f"Failed to generate cache key for request: {request}")
            return None

        if self.enable_memory_cache and key in self.memory_cache:
            with self._lock:
                response = self.memory_cache[key]
        elif self.enable_disk_cache and key in self.disk_cache:
            # Found on disk but not in memory cache, add to memory cache
            response = self._decode_disk_value(self.disk_cache[key])
            if self.enable_memory_cache:
                with self._lock:
                    self.memory_cache[key] = response
        else:
            if self.enable_disk_cache and self.default_ttl is not None:
                # Lazily purge expired on-disk entries to keep the store trim.
                self.disk_cache.expire()
            return None

        response = copy.deepcopy(response)
        if hasattr(response, "usage"):
            # Clear the usage data when cache is hit, because no LM call is made
            response.usage = {}
        return response

    def put(
        self,
        request: Dict[str, Any],
        value: Any,
        ignored_args_for_cache_key: Optional[list[str]] = None,
        enable_memory_cache: bool = True,
    ) -> None:
        try:
            key = self.cache_key(request, ignored_args_for_cache_key)
        except Exception:
            logger.debug(f"Failed to generate cache key for request: {request}")
            return

        if self.enable_memory_cache and enable_memory_cache:
            with self._lock:
                self.memory_cache[key] = value

        if self.enable_disk_cache:
            try:
                disk_value = self._encode_disk_value(value)
                if self.default_ttl is not None:
                    self.disk_cache.set(key, disk_value, expire=self.default_ttl)
                else:
                    self.disk_cache[key] = disk_value
            except Exception as e:
                # Disk cache writing can fail for different reasons, e.g. disk full or the `value` is not picklable.
                logger.debug(f"Failed to put value in disk cache: {value}, {e}")

    def _encode_disk_value(self, value: Any) -> Any:
        """Serialize `value` for on-disk storage, optionally compressing it.

        When `self.compress` is `None`, the value is stored as-is (unchanged behavior). Otherwise it is pickled,
        compressed, and prefixed with a magic header so `_decode_disk_value` can distinguish it from legacy,
        uncompressed entries.
        """
        if self.compress is None:
            return value

        payload = pickle.dumps(value)
        if self.compress == "gzip":
            payload = gzip.compress(payload)
        elif self.compress == "zlib":
            payload = zlib.compress(payload)
        codec_byte = bytes([_COMPRESSION_CODECS[self.compress]])
        return _COMPRESSION_MAGIC + codec_byte + payload

    def _decode_disk_value(self, raw: Any) -> Any:
        """Deserialize a value read from the disk cache, decompressing it if it carries our magic header."""
        if isinstance(raw, (bytes, bytearray)) and bytes(raw[:4]) == _COMPRESSION_MAGIC:
            codec_byte = raw[4]
            payload = bytes(raw[5:])
            if codec_byte == _COMPRESSION_CODECS["gzip"]:
                payload = gzip.decompress(payload)
            elif codec_byte == _COMPRESSION_CODECS["zlib"]:
                payload = zlib.decompress(payload)
            return pickle.loads(payload)
        return raw

    def set_ttl(self, seconds: Optional[int]) -> None:
        """Update the default time-to-live for future cache entries.

        Existing in-memory entries are preserved; on-disk entries already written keep their original expiry.
        """
        self.default_ttl = seconds
        if self.enable_memory_cache:
            with self._lock:
                new_memory_cache = (
                    TTLCache(maxsize=self.memory_max_entries, ttl=seconds)
                    if seconds is not None
                    else LRUCache(maxsize=self.memory_max_entries)
                )
                new_memory_cache.update(self.memory_cache)
                self.memory_cache = new_memory_cache

    def set_compression(self, codec: Optional[str]) -> None:
        """Update the compression codec used for future on-disk cache writes."""
        if codec not in (None, "gzip", "zlib"):
            raise ValueError(f"Unsupported compression codec: {codec}. Expected one of: None, 'gzip', 'zlib'.")
        self.compress = codec

    def reset_memory_cache(self) -> None:
        if not self.enable_memory_cache:
            return

        with self._lock:
            self.memory_cache.clear()

    def save_memory_cache(self, filepath: str) -> None:
        if not self.enable_memory_cache:
            return

        with self._lock:
            with open(filepath, "wb") as f:
                cloudpickle.dump(self.memory_cache, f)

    def load_memory_cache(self, filepath: str) -> None:
        if not self.enable_memory_cache:
            return

        with self._lock:
            with open(filepath, "rb") as f:
                self.memory_cache = cloudpickle.load(f)


def request_cache(
